zones = {
    "title": "Information Retrieval Basics",
    "body": "This chapter covers indexing and ranking.",
    "metadata": "Author: Salton, Date: 1975"
}

weights = {"title": 0.7, "body": 0.2, "metadata": 0.1}

def score_by_zone(query):
    total = 0
    for zone, text in zones.items():
        if query.lower() in text.lower():
            total += weights[zone]
    return round(total, 2)

print(f"Searching for 'Information': {score_by_zone('Information')}")
print(f"Searching for 'Salton': {score_by_zone('Salton')}")
